import{c as r,Q as t,j as a,m as o}from"./chunks/framework.ABl80aB6.js";const n="/pr-preview/pr-207/diagrams/pm-onion-lgt.svg",s="/pr-preview/pr-207/diagrams/pm-onion-drk.svg",i="/pr-preview/pr-207/diagrams/high-level-arch-lgt.svg",c="/pr-preview/pr-207/diagrams/high-level-arch-drk.svg",v=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/architecture.md","filePath":"concepts/architecture.md"}'),h={name:"concepts/architecture.md"};function p(l,e,d,m,u,g){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Platform Mesh is a composable platform built on the Kubernetes Resource Model. It provides one mechanism for offering, discovering, ordering, and managing services from different providers.</p><h2 id="component-layers" tabindex="-1">Component layers <a class="header-anchor" href="#component-layers" aria-label="Permalink to &quot;Component layers&quot;">​</a></h2><div class="onion-light"><p><img src="'+n+'" alt="Platform Mesh onion architecture diagram"></p></div><div class="onion-dark"><p><img src="'+s+'" alt="Platform Mesh onion architecture diagram"></p></div><p>The <strong>UI layer</strong> includes the <a href="/pr-preview/pr-207/reference/components/portal.html">Platform Mesh Portal</a> and the <a href="/pr-preview/pr-207/reference/components/kubernetes-graphql-gateway.html">Kubernetes GraphQL gateway</a>. The Portal is the consumer-facing experience. The gateway exposes Platform Mesh and kcp resources through GraphQL for UI clients.</p><p>The <strong>core control plane</strong> is <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>. Platform Mesh uses kcp workspaces, APIExports, and APIBindings as its control-plane substrate. The account operator maps Platform Mesh accounts to that workspace hierarchy.</p><p>The <strong>identity and authorization layer</strong> uses <a href="https://www.keycloak.org" target="_blank" rel="noreferrer">Keycloak</a> for OpenID Connect authentication and <a href="https://openfga.dev" target="_blank" rel="noreferrer">OpenFGA</a> for relationship-based authorization.</p><p>The <strong>deployment and supply chain layer</strong> uses Flux and OCM to deliver and reconcile platform components.</p><p>The <strong>connectivity layer</strong> connects provider runtimes to the mesh. <a href="https://docs.kcp.io/api-syncagent/" target="_blank" rel="noreferrer">api-syncagent</a> is the low-effort CRD-based path. <a href="https://github.com/kubernetes-sigs/multicluster-runtime" target="_blank" rel="noreferrer">multicluster-runtime</a> is the custom-controller path. <a href="https://kube-bind.io" target="_blank" rel="noreferrer">kube-bind</a> can be used where APIs need to be projected into regular Kubernetes clusters.</p><h2 id="component-interaction" tabindex="-1">Component interaction <a class="header-anchor" href="#component-interaction" aria-label="Permalink to &quot;Component interaction&quot;">​</a></h2><div class="arch-light"><p><img src="'+i+'" alt="Platform Mesh high-level architecture"></p></div><div class="arch-dark"><p><img src="'+c+'" alt="Platform Mesh high-level architecture"></p></div><p>A typical request starts in the <a href="/pr-preview/pr-207/reference/components/portal.html">portal</a>. The portal calls the <a href="/pr-preview/pr-207/reference/components/kubernetes-graphql-gateway.html">Kubernetes GraphQL gateway</a>, which translates the request into Kubernetes Resource Model operations against a kcp workspace. kcp authenticates the request through Keycloak and authorizes it through Kubernetes RBAC and OpenFGA-backed authorization.</p><p>When a consumer creates a resource in their workspace, the resource exists in kcp through an APIBinding to a provider APIExport. A provider-side integration mechanism synchronizes the desired state to the provider runtime. The provider operator reconciles the real service and reports status back through the same control-plane path.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./why-platform-mesh.html">Why Platform Mesh?</a></li><li><a href="./control-planes.html">Control planes</a></li><li><a href="./integration-paths.html">Integration paths</a></li><li><a href="/pr-preview/pr-207/reference/components/">Component reference</a></li></ul>',17)])])}const k=r(h,[["render",p]]);export{v as __pageData,k as default};
